(window.webpackJsonp=window.webpackJsonp||[]).push([[3],{285:function(t,e,i){"use strict";i.r(e),e.default=[{title:"使用Git Bash进行Git 操作",path:"/posts/git.html",strippedContent:" ## 使用Git Bash进行Git 操作    ### 查看当前文件副本状态  ``` bash  $ git status  On branch develop  Your branch is up-to-date with 'origin/develop'.  Changes not staged for commit:    (use \"git add <file>...\" to update what will be committed)    (use \"git checkout -- <file>...\" to discard changes in working directory)            modified:   test.txt    no changes added to commit (use \"git add\" and/or \"git commit -a\")    ```    ### 将文件添加至暂存区  ``` bash  $ git add test.txt  # 如果没有任何提示，当前命令操作成功  ```    ### 将文件从暂存区中移除  ``` bash  $ git reset head test.txt  Unstaged changes after reset:  M       test.txt  ```    ### 恢复文件至最近一个版本的状态，并放弃更改  ``` bash  $ git checkout test.txt  ```    ### 将暂存区文件提交至版本库  ``` bash  $ git commit -m '修改test文件'  [develop 5902113] 修改test文件   1 file changed, 3 insertions(+), 1 deletion(-)  # commit命令只会提交暂存区的文件，未添加进暂存区的文件不会被commit命令提交  # ###########可以看到，提交后返回一些信息  # 当前是在哪个分支（develop）提交的   # 本次提交的完整 SHA-1 # 校验和是什么（5902113）  # 以及在本次提交中，有多少文件修订过，多少行添改和删改过。  ```    ### 跳过暂存，直接将工作副本提交至版本库  ``` bash  $ git commit -a -m 'added new benchmarks'  [master 83e38c7] added new benchmarks   1 files changed, 5 insertions(+)    # 似乎不会提交未纳入版本控制的文件  # eg:新建了一个foo.txt，没有添加进暂存区  # 那么commit -a将不会为foo.txt创建版本，也不会提交此文件  ```    ### 创建文件夹和文件  ``` bash  # 创建文件夹  $ mkdir .note  # 在桌面GUI下，无法创建以“.”开头的文件夹和文件    # 创建文件  $ touch .gitignore    # 查看文件  $ cat .gitignore  # floders  .vs/    # Git Bash下运行的命令有些与Linux命令名称一致，有些与Windows命令名称一致  ```    ### 文本比较  ``` bash  $ git diff  diff --git a/foo.txt b/foo.txt  index 2974b83..e8224ee 100644  --- a/foo.txt  +++ b/foo.txt  @@ -1 +1,3 @@  -add line 1  \\ No newline at end of file  +----foo.txt  +add line 1  +add line 2  \\ No newline at end of file    ```    # 删除文件并移除版本控制  ``` bash  $ git rm foo.txt  rm 'foo.txt'    $ git status  On branch develop  Your branch is ahead of 'origin/develop' by 3 commits.    (use \"git push\" to publish your local commits)  Changes to be committed:    (use \"git reset HEAD <file>...\" to unstage)            deleted:    foo.txt    $ git commit -m '删除foo.txt'  [develop fb06b92] 删除foo.txt   1 file changed, 3 deletions(-)   delete mode 100644 foo.txt    ```    # 移除版本控制但不删除文件  ``` bash  $ git rm --cached bar.txt  rm 'bar.txt'    $ git commit -a -m '移除bar.txt版本控制'    # 移除类型文件/目录版本控制  $ git rm log/\\*.log    ```    # 文件重命名  ``` bash  $ dir  bar.txt  test.txt    $ git mv test.txt flus.txt    $ dir  bar.txt  flus.txt    $ git status  On branch develop  Your branch is ahead of 'origin/develop' by 6 commits.    (use \"git push\" to publish your local commits)  Changes to be committed:    (use \"git reset HEAD <file>...\" to unstage)            renamed:    test.txt -> flus.txt    #其实，运行 git mv 就相当于运行了下面三条命令：  $ mv README.txt README  $ git rm README.txt  $ git add README  ```  "},{title:"创建圆头矩形",path:"/posts/%E5%88%9B%E5%BB%BA%E5%9C%86%E5%A4%B4%E7%9F%A9%E5%BD%A2.html",strippedContent:' # 创建两端半圆的长方形 #  这里介绍创建一个两头半圆的横向矩形的方法，我称之为“圆头矩形”，就行下面这样。但是又不想给一个确定的高度值，或者说我想让圆头矩形可以自适应页面调整大小。    ## 首先一个非百分之百宽度的div    其实一个盒子就够了，这里加入class=box的div是要让class=tiao的div水平居中  ```  <div class="box">      <div class="tiao">      </div>  </div>  ```    ## css样式  ```  <style>      .box {          text-align: center      }        .tiao {          width: 200px;          display: inline-block;          background: rgba(0, 0, 0, .7);      }        .tiao::before {          content: \'\';          display: inline-block;          width: 20%;          padding-top: 20%;          margin-left: -10%;          float: left;          border-radius: 50%;      }        .tiao::after {          content: \'\';          display: inline-block;          width: 20%;          padding-top: 20%;          margin-right: -10%;          float: right;          border-radius: 50%;      }  </style>  ```  ## 创建两段圆形的形状的步骤  ### 1 行内元素盒子tiao  * 一个具有初始宽度的行内元素，设置其宽度非100%，以下称tiao    ### 2 设置tiao伪元素befor和after  * width和padding-top属性值设置为相同值，这个值决定了tiao形状的高度  * 背景颜色和条的别境颜色一致  * before元素margin-left为before元素width取负值的一般  * after元素margin-right为after元素width取负值的一般    ### 3. Tips  1. tiao元素display属性设置其他值没有测试，以上设置为inline-block可以通过设置父元素box的text-align属性为center方便地实现tiao居中。  2. 这种实现背景色不支持半透明，否则会出现重叠，目前还没有想到解决办法    # 要求不那么严格的圆头矩形  当然非强迫症患者仍然有另一种可能，那就是直接设置border-radius属性的水平和垂直半径不相同即可。像下面这样：  <div style="background:#cbcbcb;width:50%;height:50px;border-radius:6%/50%;margin:0 auto;"></div>    ## 代码  ```  <style>  .box{      background:#cbcbcb;      width:50%;      height:50px;      border-radius:6%/50%;      margin:0 auto;  }  </style>    <div class="box"></div>  ```    ## Tips  这种方式写法简单，不断调试border-radius的水平和垂直方向上的取值达到满意的效果。'},{title:"SQL 代码片段",path:"/posts/SQL.html",strippedContent:" ### 查询当前数据库表的所有字段  ``` sql  select t.name,c.name from sysobjects t  left join syscolumns c on c.id = t.id  where t.xtype = 'U'  ```"},{title:"C# 代码片段",path:"/posts/CSharp.html",strippedContent:' ### 为Linq的Where增加重载以支持多个参数  ``` cs  //定义扩展  public static class EX  {      public static List<Tsource> Where<Tsource,T2>(this IEnumerable<Tsource> items,Func<Tsource, T2, bool> func, T2 temp)      {          List<Tsource> list = new List<Tsource>();          foreach (Tsource item in items)          {              if (func(item, temp))              {                  list.Add(item);              }          }          return list;      }  }    //使用扩展   class Program  {      static void Main(string[] args)      {      \tList<string> stringItems = new List<string>{ "张三","李四","王五","马六","王二麻子","钱掌柜","葫芦棍子","屎蛋" };  \t\t  \t\t//筛选名字长度          int limitLength = 2;          //定义筛选器          Func<string, int, bool> func = (origin, temp) => origin.Length > temp;          //调用扩展          List<string> res = stringItems.MyWhere(func,limitLength);          foreach (var item in res)          {              Console.WriteLine("名字长度大于2的项目：" + item);          }            Console.Read();  \t}  }  ```      ### 操作系统中线程的数据结构包括的主要内容  * Thread内核数据结构，主要OSId（）线程的ID,Context上下文（存放了CPU寄存器相关的变量）    ### 应用程序域  Application Domain 用于个里再同一个计算机上运行的不同程序'},{title:"Javascript文本HTML编码",path:"/posts/Javascript%E6%96%87%E6%9C%ACHTML%E7%BC%96%E7%A0%81.html",strippedContent:' # 对字符串进行HTML编码和解码的JavaScript函数  ## 将字符串中HTML标签转换HTML编码（编码）  ``` javascript  function HtmlEncode(str) {       var t = document.createElement("div");       t.textContent ? t.textContent = str : t.innerText = str;       return t.innerHTML;   }   ```  如下HTML片段：  ``` html  <div class="txt">      <p>nihao</p>      <span>          nihao      </span>  </div>  ```  经调用HtmlEncode函数得到的结果  ```  &lt;div class="txt"&gt;<br>\t\t&lt;p&gt;nihao&lt;/p&gt;<br>\t\t&lt;span&gt;<br>\t\t\tnihao<br>\t\t&lt;/span&gt;<br>\t&lt;/div&gt;  ```  HTML片段中的空格会被保留，换行符会被替换成<code>&lt;br&gt;</code>标签    ## 将HTML编码转换成HTML代码片段（解码）  ``` javascript  function HtmlDecode(str) {       var t = document.createElement("div");       t.innerHTML = str;       return t.innerText || t.textContent   }   ```'}]}}]);